     1â†’<!DOCTYPE html>
     2â†’<html lang="en">
     3â†’<head>
     4â†’  <meta charset="UTF-8">
     5â†’  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6â†’  <title>Claude Code Voice Controller</title>
     7â†’  <style>
     8â†’    * { box-sizing: border-box; margin: 0; padding: 0; }
     9â†’    body {
    10â†’      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    11â†’      background: #0f0f0f;
    12â†’      color: #e0e0e0;
    13â†’      min-height: 100vh;
    14â†’    }
    15â†’    .container { max-width: 1200px; margin: 0 auto; padding: 20px; }
    16â†’
    17â†’    /* Header */
    18â†’    .header {
    19â†’      display: flex;
    20â†’      justify-content: space-between;
    21â†’      align-items: center;
    22â†’      padding: 20px;
    23â†’      background: #1a1a1a;
    24â†’      border-radius: 8px;
    25â†’      margin-bottom: 20px;
    26â†’    }
    27â†’    .header h1 { font-size: 20px; font-weight: 600; }
    28â†’    .session-info { font-size: 12px; color: #888; margin-top: 5px; }
    29â†’    .status-badge {
    30â†’      padding: 6px 12px;
    31â†’      border-radius: 20px;
    32â†’      font-size: 12px;
    33â†’      font-weight: 600;
    34â†’    }
    35â†’    .status-badge.connected { background: #1a8f1a; color: white; }
    36â†’    .status-badge.disconnected { background: #8f1a1a; color: white; }
    37â†’    .status-badge.processing { background: #1a5a8f; color: white; }
    38â†’
    39â†’    /* Grid Layout */
    40â†’    .grid {
    41â†’      display: grid;
    42â†’      grid-template-columns: 1fr 1fr;
    43â†’      gap: 20px;
    44â†’    }
    45â†’    .full-width { grid-column: 1 / -1; }
    46â†’
    47â†’    /* Panels */
    48â†’    .panel {
    49â†’      background: #1a1a1a;
    50â†’      border-radius: 8px;
    51â†’      padding: 20px;
    52â†’      border: 1px solid #333;
    53â†’    }
    54â†’    .panel h2 {
    55â†’      font-size: 14px;
    56â†’      text-transform: uppercase;
    57â†’      letter-spacing: 1px;
    58â†’      margin-bottom: 15px;
    59â†’      color: #888;
    60â†’    }
    61â†’
    62â†’    /* Input Area */
    63â†’    .input-area {
    64â†’      display: flex;
    65â†’      gap: 10px;
    66â†’      margin-bottom: 15px;
    67â†’    }
    68â†’    .input-field {
    69â†’      flex: 1;
    70â†’      padding: 12px;
    71â†’      background: #0a0a0a;
    72â†’      border: 1px solid #333;
    73â†’      border-radius: 4px;
    74â†’      color: #e0e0e0;
    75â†’      font-family: inherit;
    76â†’    }
    77â†’    .input-field:focus {
    78â†’      outline: none;
    79â†’      border-color: #4a9eff;
    80â†’    }
    81â†’    .btn {
    82â†’      padding: 10px 20px;
    83â†’      border: none;
    84â†’      border-radius: 4px;
    85â†’      font-weight: 600;
    86â†’      cursor: pointer;
    87â†’      transition: opacity 0.2s;
    88â†’    }
    89â†’    .btn:hover { opacity: 0.8; }
    90â†’    .btn-primary { background: #4a9eff; color: white; }
    91â†’    .btn-interrupt { background: #8f5a1a; color: white; }
    92â†’
    93â†’    /* Response */
    94â†’    .response {
    95â†’      min-height: 200px;
    96â†’      max-height: 400px;
    97â†’      overflow-y: auto;
    98â†’      padding: 15px;
    99â†’      background: #0a0a0a;
   100â†’      border-radius: 4px;
   101â†’      white-space: pre-wrap;
   102â†’      font-family: 'SF Mono', 'Consolas', monospace;
   103â†’      font-size: 13px;
   104â†’      line-height: 1.5;
   105â†’    }
   106â†’
   107â†’    /* Tool Calls */
   108â†’    .tool-call {
   109â†’      display: flex;
   110â†’      align-items: center;
   111â†’      padding: 10px;
   112â†’      background: #0a0a0a;
   113â†’      border-radius: 4px;
   114â†’      margin-bottom: 8px;
   115â†’      border-left: 3px solid #555;
   116â†’    }
   117â†’    .tool-call.pending { border-left-color: #aa8800; }
   118â†’    .tool-call.approved { border-left-color: #1a8f1a; }
   119â†’    .tool-call.denied { border-left-color: #8f1a1a; }
   120â†’    .tool-call.executing { border-left-color: #1a5a8f; }
   121â†’    .tool-call.completed { border-left-color: #555; }
   122â†’
   123â†’    .tool-name {
   124â†’      font-weight: 600;
   125â†’      margin-right: 10px;
   126â†’      min-width: 100px;
   127â†’    }
   128â†’    .tool-input {
   129â†’      font-family: monospace;
   130â†’      font-size: 12px;
   131â†’      color: #888;
   132â†’      flex: 1;
   133â†’      overflow: hidden;
   134â†’      text-overflow: ellipsis;
   135â†’      white-space: nowrap;
   136â†’    }
   137â†’    .tool-status {
   138â†’      font-size: 11px;
   139â†’      padding: 2px 8px;
   140â†’      border-radius: 10px;
   141â†’      background: #333;
   142â†’    }
   143â†’
   144â†’    /* Permission Request */
   145â†’    .permission-request {
   146â†’      padding: 15px;
   147â†’      background: #2a1a1a;
   148â†’      border: 1px solid #8f3a3a;
   149â†’      border-radius: 4px;
   150â†’    }
   151â†’    .permission-request strong { color: #e0e0e0; }
   152â†’    .permission-request code {
   153â†’      display: block;
   154â†’      margin-top: 10px;
   155â†’      padding: 10px;
   156â†’      background: #0a0a0a;
   157â†’      border-radius: 4px;
   158â†’      font-size: 12px;
   159â†’      overflow-x: auto;
   160â†’    }
   161â†’    .permission-actions {
   162â†’      margin-top: 15px;
   163â†’      display: flex;
   164â†’      gap: 10px;
   165â†’    }
   166â†’    .btn-allow { background: #1a8f1a; color: white; }
   167â†’    .btn-deny { background: #8f1a1a; color: white; }
   168â†’
   169â†’    /* Stats */
   170â†’    .stats {
   171â†’      display: grid;
   172â†’      grid-template-columns: repeat(4, 1fr);
   173â†’      gap: 15px;
   174â†’    }
   175â†’    .stat {
   176â†’      text-align: center;
   177â†’      padding: 15px;
   178â†’      background: #0a0a0a;
   179â†’      border-radius: 4px;
   180â†’    }
   181â†’    .stat-value {
   182â†’      font-size: 24px;
   183â†’      font-weight: 700;
   184â†’      color: #4a9eff;
   185â†’    }
   186â†’    .stat-label {
   187â†’      font-size: 11px;
   188â†’      text-transform: uppercase;
   189â†’      color: #888;
   190â†’      margin-top: 5px;
   191â†’    }
   192â†’
   193â†’    /* Messages Log */
   194â†’    .messages-log {
   195â†’      max-height: 300px;
   196â†’      overflow-y: auto;
   197â†’      padding: 10px;
   198â†’      background: #0a0a0a;
   199â†’      border-radius: 4px;
   200â†’      font-family: monospace;
   201â†’      font-size: 12px;
   202â†’    }
   203â†’    .log-entry {
   204â†’      padding: 5px 0;
   205â†’      border-bottom: 1px solid #222;
   206â†’    }
   207â†’    .log-entry:last-child { border-bottom: none; }
   208â†’    .log-time { color: #666; margin-right: 10px; }
   209â†’    .log-type { color: #4a9eff; margin-right: 10px; }
   210â†’    .log-content { color: #888; }
   211â†’  </style>
   212â†’</head>
   213â†’<body>
   214â†’  <div class="container">
   215â†’    <!-- Header -->
   216â†’    <div class="header">
   217â†’      <div>
   218â†’        <h1>Claude Code Voice Controller</h1>
   219â†’        <div class="session-info">Session: <span id="session-id">Not connected</span></div>
   220â†’      </div>
   221â†’      <div>
   222â†’        <span id="connection-status" class="status-badge disconnected">Disconnected</span>
   223â†’      </div>
   224â†’    </div>
   225â†’
   226â†’    <div class="grid">
   227â†’      <!-- Input -->
   228â†’      <div class="panel full-width">
   229â†’        <h2>Send Message to Claude</h2>
   230â†’        <div class="input-area">
   231â†’          <input type="text" id="message-input" class="input-field" placeholder="Type a message to send to Claude Code..." />
   232â†’          <button id="btn-send" class="btn btn-primary">Send</button>
   233â†’        </div>
   234â†’      </div>
   235â†’
   236â†’      <!-- Response -->
   237â†’      <div class="panel">
   238â†’        <h2>Claude's Response</h2>
   239â†’        <div id="response" class="response">Waiting for Claude to respond...</div>
   240â†’      </div>
   241â†’
   242â†’      <!-- Messages Log -->
   243â†’      <div class="panel">
   244â†’        <h2>Message Log</h2>
   245â†’        <div id="messages-log" class="messages-log">
   246â†’          <div style="color: #666; text-align: center; padding: 20px;">No messages yet</div>
   247â†’        </div>
   248â†’      </div>
   249â†’
   250â†’      <!-- Stats -->
   251â†’      <div class="panel full-width">
   252â†’        <h2>Session Stats</h2>
   253â†’        <div class="stats">
   254â†’          <div class="stat">
   255â†’            <div id="stat-turns" class="stat-value">0</div>
   256â†’            <div class="stat-label">Turns</div>
   257â†’          </div>
   258â†’          <div class="stat">
   259â†’            <div id="stat-tokens" class="stat-value">0</div>
   260â†’            <div class="stat-label">Tokens</div>
   261â†’          </div>
   262â†’          <div class="stat">
   263â†’            <div id="stat-cost" class="stat-value">$0.00</div>
   264â†’            <div class="stat-label">Cost</div>
   265â†’          </div>
   266â†’          <div class="stat">
   267â†’            <div id="stat-tools" class="stat-value">0</div>
   268â†’            <div class="stat-label">Tool Calls</div>
   269â†’          </div>
   270â†’        </div>
   271â†’      </div>
   272â†’
   273â†’      <!-- Tool Calls -->
   274â†’      <div class="panel">
   275â†’        <h2>Tool Calls</h2>
   276â†’        <div id="tool-calls">
   277â†’          <div style="color: #888; text-align: center; padding: 20px;">
   278â†’            No tool calls yet
   279â†’          </div>
   280â†’        </div>
   281â†’      </div>
   282â†’
   283â†’      <!-- Pending Permission -->
   284â†’      <div class="panel">
   285â†’        <h2>Pending Permission</h2>
   286â†’        <div id="permission-area">
   287â†’          <div style="color: #888; text-align: center; padding: 20px;">
   288â†’            No pending permissions
   289â†’          </div>
   290â†’        </div>
   291â†’      </div>
   292â†’
   293â†’      <!-- Control -->
   294â†’      <div class="panel full-width">
   295â†’        <h2>Control</h2>
   296â†’        <button id="btn-interrupt" class="btn btn-interrupt">Interrupt Current Action</button>
   297â†’      </div>
   298â†’    </div>
   299â†’  </div>
   300â†’
   301â†’  <script>
   302â†’    // State
   303â†’    const state = {
   304â†’      connected: false,
   305â†’      sessionId: null,
   306â†’      response: '',
   307â†’      toolCalls: [],
   308â†’      pendingPermission: null,
   309â†’      stats: {
   310â†’        turns: 0,
   311â†’        tokens: 0,
   312â†’        cost: 0,
   313â†’        tools: 0
   314â†’      },
   315â†’      messages: []
   316â†’    }
   317â†’
   318â†’    // DOM Elements
   319â†’    const elements = {
   320â†’      connectionStatus: document.getElementById('connection-status'),
   321â†’      sessionId: document.getElementById('session-id'),
   322â†’      messageInput: document.getElementById('message-input'),
   323â†’      btnSend: document.getElementById('btn-send'),
   324â†’      response: document.getElementById('response'),
   325â†’      toolCalls: document.getElementById('tool-calls'),
   326â†’      permissionArea: document.getElementById('permission-area'),
   327â†’      btnInterrupt: document.getElementById('btn-interrupt'),
   328â†’      statTurns: document.getElementById('stat-turns'),
   329â†’      statTokens: document.getElementById('stat-tokens'),
   330â†’      statCost: document.getElementById('stat-cost'),
   331â†’      statTools: document.getElementById('stat-tools'),
   332â†’      messagesLog: document.getElementById('messages-log')
   333â†’    }
   334â†’
   335â†’    // SSE Connection
   336â†’    function connectSSE() {
   337â†’      const eventSource = new EventSource('/api/events')
   338â†’
   339â†’      eventSource.addEventListener('connect', (e) => {
   340â†’        console.log('SSE connected')
   341â†’      })
   342â†’
   343â†’      eventSource.addEventListener('message', (e) => {
   344â†’        try {
   345â†’          const event = JSON.parse(e.data)
   346â†’          handleEvent(event)
   347â†’        } catch (err) {
   348â†’          console.error('Failed to parse event:', err)
   349â†’        }
   350â†’      })
   351â†’
   352â†’      eventSource.onerror = (err) => {
   353â†’        console.error('SSE error:', err)
   354â†’      }
   355â†’
   356â†’      return eventSource
   357â†’    }
   358â†’
   359â†’    // Event Handlers
   360â†’    function handleEvent(event) {
   361â†’      console.log('Event:', event.type, event.data)
   362â†’
   363â†’      // Add to message log
   364â†’      addMessageLog(event.type, event.data)
   365â†’
   366â†’      switch (event.type) {
   367â†’        case 'connection':
   368â†’          if (event.data.type === 'connected') {
   369â†’            handleConnected(event.data)
   370â†’          } else if (event.data.type === 'disconnected') {
   371â†’            handleDisconnected(event.data)
   372â†’          }
   373â†’          break
   374â†’        case 'system_init':
   375â†’          handleSystemInit(event.data)
   376â†’          break
   377â†’        case 'assistant':
   378â†’          handleAssistant(event.data)
   379â†’          break
   380â†’        case 'stream_event':
   381â†’          handleStreamEvent(event.data)
   382â†’          break
   383â†’        case 'result':
   384â†’          handleResult(event.data)
   385â†’          break
   386â†’        case 'permission_request':
   387â†’          handlePermissionRequest(event.data)
   388â†’          break
   389â†’        case 'permission_response':
   390â†’          handlePermissionResponse(event.data)
   391â†’          break
   392â†’        case 'tool_progress':
   393â†’          handleToolProgress(event.data)
   394â†’          break
   395â†’        case 'status_change':
   396â†’          handleStatusChange(event.data)
   397â†’          break
   398â†’      }
   399â†’    }
   400â†’
   401â†’    function handleConnected(data) {
   402â†’      state.connected = true
   403â†’      updateConnectionStatus('connected')
   404â†’    }
   405â†’
   406â†’    function handleDisconnected(data) {
   407â†’      state.connected = false
   408â†’      updateConnectionStatus('disconnected')
   409â†’    }
   410â†’
   411â†’    function handleSystemInit(data) {
   412â†’      state.sessionId = data.sessionId
   413â†’      elements.sessionId.textContent = data.sessionId?.slice(-8) || 'Unknown'
   414â†’      updateConnectionStatus('connected')
   415â†’    }
   416â†’
   417â†’    function handleAssistant(data) {
   418â†’      if (data.text) {
   419â†’        state.response = data.text
   420â†’        elements.response.textContent = data.text
   421â†’      }
   422â†’    }
   423â†’
   424â†’    function handleStreamEvent(data) {
   425â†’      // Streaming delta update
   426â†’      if (data.delta) {
   427â†’        elements.response.textContent = (state.response + data.text).trim()
   428â†’        state.response = elements.response.textContent
   429â†’      }
   430â†’    }
   431â†’
   432â†’    function handleResult(data) {
   433â†’      state.stats.turns = data.num_turns || 0
   434â†’      state.stats.tokens = data.usage?.input_tokens + data.usage?.output_tokens || 0
   435â†’      state.stats.cost = data.total_cost_usd || 0
   436â†’      updateStats()
   437â†’
   438â†’      if (data.is_error) {
   439â†’        elements.response.textContent += '\n\n[ERROR]: ' + (data.errors?.join('\n') || 'Unknown error')
   440â†’      }
   441â†’    }
   442â†’
   443â†’    function handlePermissionRequest(data) {
   444â†’      state.pendingPermission = data
   445â†’      renderPermissionRequest()
   446â†’    }
   447â†’
   448â†’    function handlePermissionResponse(data) {
   449â†’      if (state.pendingPermission?.tool_use_id === data.tool_use_id || state.pendingPermission?.request_id === data.request_id) {
   450â†’        state.pendingPermission = null
   451â†’        renderPermissionRequest()
   452â†’      }
   453â†’    }
   454â†’
   455â†’    function handleToolProgress(data) {
   456â†’      const existing = state.toolCalls.find(t => t.toolUseId === data.tool_use_id)
   457â†’      if (existing) {
   458â†’        existing.status = data.status || 'executing'
   459â†’        existing.elapsed = data.elapsed
   460â†’      } else {
   461â†’        state.toolCalls.push({
   462â†’          toolUseId: data.tool_use_id,
   463â†’          toolName: data.tool_name,
   464â†’          status: data.status || 'executing',
   465â†’          elapsed: data.elapsed
   466â†’        })
   467â†’      }
   468â†’      renderToolCalls()
   469â†’    }
   470â†’
   471â†’    function handleStatusChange(data) {
   472â†’      updateConnectionStatus(data.status === 'idle' ? 'connected' : data.status)
   473â†’    }
   474â†’
   475â†’    // UI Updates
   476â†’    function updateConnectionStatus(status) {
   477â†’      elements.connectionStatus.className = `status-badge ${status}`
   478â†’      elements.connectionStatus.textContent = status.charAt(0).toUpperCase() + status.slice(1)
   479â†’    }
   480â†’
   481â†’    function updateStats() {
   482â†’      elements.statTurns.textContent = state.stats.turns
   483â†’      elements.statTokens.textContent = state.stats.tokens.toLocaleString()
   484â†’      elements.statCost.textContent = '$' + state.stats.cost.toFixed(4)
   485â†’      elements.statTools.textContent = state.toolCalls.length
   486â†’    }
   487â†’
   488â†’    function renderToolCalls() {
   489â†’      if (state.toolCalls.length === 0) {
   490â†’        elements.toolCalls.innerHTML = '<div style="color: #888; text-align: center; padding: 20px;">No tool calls yet</div>'
   491â†’        return
   492â†’      }
   493â†’
   494â†’      elements.toolCalls.innerHTML = state.toolCalls.map(tool => `
   495â†’        <div class="tool-call ${tool.status}">
   496â†’          <span class="tool-name">${tool.toolName}</span>
   497â†’          <span class="tool-status">${tool.status}${tool.elapsed ? ` (${tool.elapsed.toFixed(1)}s)` : ''}</span>
   498â†’        </div>
   499â†’      `).join('')
   500â†’    }
   501â†’
   502â†’    function renderPermissionRequest() {
   503â†’      if (!state.pendingPermission) {
   504â†’        elements.permissionArea.innerHTML = '<div style="color: #888; text-align: center; padding: 20px;">No pending permissions</div>'
   505â†’        return
   506â†’      }
   507â†’
   508â†’      const req = state.pendingPermission
   509â†’      elements.permissionArea.innerHTML = `
   510â†’        <div class="permission-request">
   511â†’          <strong>Tool:</strong> ${req.tool_name}<br>
   512â†’          <strong>Input:</strong> <code>${JSON.stringify(req.input, null, 2)}</code>
   513â†’          <div class="permission-actions">
   514â†’            <button class="btn btn-allow" onclick="respondPermission(true)">Allow</button>
   515â†’            <button class="btn btn-deny" onclick="respondPermission(false)">Deny</button>
   516â†’          </div>
   517â†’        </div>
   518â†’      `
   519â†’    }
   520â†’
   521â†’    function addMessageLog(type, data) {
   522â†’      const timestamp = new Date().toLocaleTimeString()
   523â†’      state.messages.unshift({ type, data, timestamp })
   524â†’      if (state.messages.length > 50) state.messages.pop()
   525â†’
   526â†’      renderMessageLog()
   527â†’    }
   528â†’
   529â†’    function renderMessageLog() {
   530â†’      if (state.messages.length === 0) {
   531â†’        elements.messagesLog.innerHTML = '<div style="color: #666; text-align: center; padding: 20px;">No messages yet</div>'
   532â†’        return
   533â†’      }
   534â†’
   535â†’      elements.messagesLog.innerHTML = state.messages.slice(0, 20).map(msg => {
   536â†’        const content = typeof msg.data === 'object' ? JSON.stringify(msg.data).substring(0, 100) : String(msg.data).substring(0, 100)
   537â†’        return `
   538â†’          <div class="log-entry">
   539â†’            <span class="log-time">${msg.timestamp}</span>
   540â†’            <span class="log-type">${msg.type}</span>
   541â†’            <span class="log-content">${content}</span>
